    SymbolInfo(String name, SymKind kind, Token declaredAt, int arity) {
      this.name = name;
      this.kind = kind;
      this.declaredAt = declaredAt;
      this.arity = arity;
    }

    boolean isConst() { return kind == SymKind.CONST; }
